  return <View style={styles.wrap} accessibilityRole="image" accessibilityLabel="Animated wave loader (water filling shape)"><Canvas style={{width: size, height: size}}><Rect x={0} y={0} width={size} height={size} color="#020617" /><Group opacity={0.92}><Circle cx={size * 0.5} cy={size * 0.5} r={size * 0.32} color="#38bdf8" /><Circle cx={size * 0.38} cy={size * 0.42} r={size * 0.18} color="#a7f3d0" /><Paint color="#ffffff" style="stroke" strokeWidth={2} /></Group></Canvas></View>;
}
