// rn-269: accessible mobile chart for Annotated event line on time-series
import React, {useMemo} from 'react';
import {Text, View} from 'react-native';
import {Canvas, Path, Skia} from '@shopify/react-native-skia';
export function AnnotatedEventLineOnTimeSeriesChart({points = []}) {
  const path = useMemo(() => { const p = Skia.Path.Make(); p.moveTo(12, 72); points.forEach((pt, i) => p.lineTo(12 + i * 18, 72 - pt.value)); return p; }, [points]);
  const summary = points.length ? `${points.length} plotted values` : 'No chart data';
  return <View accessible accessibilityRole="image" accessibilityLabel={`Annotated event line on time-series: ${summary}`}><Canvas style={{height:120,width:'100%'}}><Path path={path} color="#0f766e" style="stroke" strokeWidth={4}/></Canvas><Text accessibilityLiveRegion="polite">{summary}</Text></View>;
}

